/**
 * AIC (Artificial Intelligence Command) Report System
 * Strategic intelligence and status reports generated by the AIC
 * @tag #aic #report #intelligence #strategy
 */

// ============================================================================
// TYPES
// ============================================================================

export type AICReportCategory =
  | 'intel'
  | 'threat'
  | 'strategic'
  | 'economic'
  | 'military'
  | 'diplomatic'
  | 'research'
  | 'expansion'
  | 'internal';

export type AICReportSeverity =
  | 'informational'
  | 'advisory'
  | 'warning'
  | 'critical'
  | 'urgent';

export type AICReportStatus =
  | 'pending'
  | 'reviewed'
  | 'actioned'
  | 'archived'
  | 'escalated';

export type AICReportTrigger =
  | 'scheduled'
  | 'event_detected'
  | 'threshold_exceeded'
  | 'player_requested'
  | 'system_alert'
  | 'intel_update';

export interface AICReportSource {
  entityId: string;
  entityName: string;
  entityType: 'sensor_network' | 'spy_network' | 'fleet_intel' | 'economic_analysis' | 'diplomatic_corps' | 'research_division' | 'internal_affairs' | 'strategic_command';
  reliability: number; // 0-1
}

export interface AICReportData {
  id: string;
  category: AICReportCategory;
  severity: AICReportSeverity;
  status: AICReportStatus;
  trigger: AICReportTrigger;
  timestamp: number;
  title: string;
  summary: string;
  details: string;
  source: AICReportSource;
  relatedEntityId?: string;
  relatedEntityType?: string;
  confidence: number; // 0-1
  recommendations: readonly string[];
  actionable: boolean;
  expiryTimestamp?: number;
}

