// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

export function getReportCategoryConfig(category: AICReportCategory): AICReportCategoryConfig | undefined {
  return AIC_REPORT_CATEGORIES.find(c => c.category === category);
}

export function getReportSeverityConfig(severity: AICReportSeverity): AICReportSeverityConfig | undefined {
  return AIC_REPORT_SEVERITIES.find(s => s.severity === severity);
}

export function getReportTemplate(templateId: string): AICReportTemplate | undefined {
  return AIC_REPORT_TEMPLATES.find(t => t.id === templateId);
}

export function getReportTemplatesByCategory(category: AICReportCategory): readonly AICReportTemplate[] {
  return AIC_REPORT_TEMPLATES.filter(t => t.category === category);
}

export function getReportsBySeverity(severity: AICReportSeverity, reports: readonly AICReportData[]): readonly AICReportData[] {
  return reports.filter(r => r.severity === severity);
}

export function getActiveReports(reports: readonly AICReportData[]): readonly AICReportData[] {
  const now = Date.now();
  return reports.filter(r =>
    r.status === 'pending' &&
    (!r.expiryTimestamp || r.expiryTimestamp > now)
  );
}

export function generateReportId(): string {
  return `aic-rpt-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`;
}

export function createAICReport(
  templateId: string,
  category: AICReportCategory,
  severity: AICReportSeverity,
  source: AICReportSource,
  title: string,
  summary: string,
  details: string,
  confidence?: number,
  relatedEntityId?: string,
  relatedEntityType?: string,
): AICReportData {
  const template = getReportTemplate(templateId);
  const categoryConfig = getReportCategoryConfig(category);
  const severityConfig = getReportSeverityConfig(severity);

  const retentionDays = categoryConfig?.defaultRetentionDays ?? 14;

  return {
    id: generateReportId(),
    category,
    severity,
    status: 'pending',
    trigger: template?.triggerType ?? 'system_alert',
    timestamp: Date.now(),
    title,
    summary,
    details,
    source,
    relatedEntityId,
    relatedEntityType,
    confidence: confidence ?? template?.baseConfidence ?? 0.5,
    recommendations: [],
    actionable: template?.actionable ?? false,
    expiryTimestamp: Date.now() + retentionDays * 24 * 60 * 60 * 1000,
  };
}
